Document.BkToCstmrStmt:

	{{msg_id}}
	{{creation_date_time}}

{% for stmt in statements %}

	{{stmt.id}}
	{% if stmt.electronic_seq_nb %}{{stmt.electronic_seq_nb}}{% endif %}
	{% if stmt.creation_date_time %}{{stmt.creation_date_time}}{% endif %}

		{% if stmt.account_id %}{% if stmt.account_iban %}{{stmt.account_iban}}{% else %}{{stmt.account_other_id}}{% endif %}{% endif %}
		{% if stmt.account_currency %}{{stmt.account_currency}}{% endif %}
		{% if stmt.account_owner_name %}{{stmt.account_owner_name}}{% endif %}
		{% if stmt.account_servicer_bic %}{{stmt.account_servicer_bic}}{% endif %}

	{% for bal in stmt.balances %}

		{{bal.type_code}}
		{{bal.amount}}
		{{bal.credit_debit_indicator}}
		{% if bal.is_datetime %}{{bal.date}}{% else %}{{bal.date}}{% endif %}

	{% endfor %}
	{% for ntry in stmt.entries %}

		{% if ntry.reference %}{{ntry.reference}}{% endif %}
		{{ntry.amount}}
		{{ntry.credit_debit_indicator}}
		{% if ntry.reversal_indicator %}true{% endif %}
		{{ntry.status}}
		{% if ntry.booking_date %}{% if ntry.booking_is_datetime %}{{ntry.booking_date}}{% else %}{{ntry.booking_date}}{% endif %}{% endif %}
		{% if ntry.value_date %}{% if ntry.value_is_datetime %}{{ntry.value_date}}{% else %}{{ntry.value_date}}{% endif %}{% endif %}
		{% if ntry.account_servicer_ref %}{{ntry.account_servicer_ref}}{% endif %}


				PMNT

					RCDT
					RRTN



		{% for tx in ntry.details %}


				{% if tx.instruction_id or tx.end_to_end_id or tx.tx_id %}

					{% if tx.instruction_id %}{{tx.instruction_id}}{% endif %}
					{% if tx.end_to_end_id %}{{tx.end_to_end_id}}{% endif %}
					{% if tx.tx_id %}{{tx.tx_id}}{% endif %}

				{% endif %}
				{% if tx.counterparty_name or tx.counterparty_account %}

					{% if tx.counterparty_name %}{{tx.counterparty_name}}{% endif %}
					{% if tx.counterparty_account %}{{tx.counterparty_account}}{% endif %}

				{% endif %}
				{% if tx.reason_code or tx.additional_info %}

					{% if tx.reason_code %}{{tx.reason_code}}{% endif %}
					{% if tx.additional_info %}{{tx.additional_info}}{% endif %}

				{% endif %}


		{% endfor %}

	{% endfor %}

{% endfor %}
